{
  "title": "संदर्भ बजट",
  "group": "टोकन प्रबंधन",
  "options": [
    {
      "text": "ज्यादा से ज्यादा जानकारी के लिए कॉन्टेक्स्ट विंडो का 95%+ उपयोग करें"
    },
    {
      "text": "पूरी विंडो भरने के बजाय आउटपुट के लिए पर्याप्त जगह (headroom) बचाकर रखें"
    },
    {
      "text": "कॉन्टेक्स्ट बजट का महत्व केवल 32K टोकन से कम मॉडल्स के लिए होता है"
    },
    {
      "text": "जब विंडो सीमा पार हो जाती है तो मॉडल स्वचालित रूप से उसे काट (truncate) देता है"
    }
  ],
  "questionProse": [
    "रिट्रीव्ड कॉन्टेक्स्ट के साथ RAG प्रॉम्प्ट बनाते समय, कॉन्टेक्स्ट बजट के लिए एक अच्छा नियम क्या है:"
  ],
  "explanationProse": [
    "कॉन्टेक्स्ट विंडो **इनपुट और आउटपुट** दोनों के लिए शेयर की जाती है। अगर आप इनपुट के लिए 90% उपयोग करते हैं, तो मॉडल के पास रिस्पॉन्स जनरेट करने के लिए विंडो का सिर्फ 10% बचता है — जिससे अक्सर आउटपुट ट्रंकेट हो जाता है या उसकी क्वालिटी खराब हो जाती है。\n\n    एक उचित हेयुरिस्टिक: पहले अपने एक्सपेक्टेड आउटपुट साइज का अनुमान लगाएं, फिर अपने इनपुट को बजट के हिसाब से काफी नीचे रखें। कई RAG टास्क के लिए इसका मतलब है कि **कुल कॉन्टेक्स्ट विंडो का 60–70% से ज्यादा इनपुट (सिस्टम प्रॉम्प्ट + हिस्ट्री + रिट्रीव्ड कॉन्टेक्स्ट) के लिए उपयोग न करें**। बाकी बजट जनरेशन और सेफ्टी मार्जिन के लिए छोड़ दें。\n\n    इसके अलावा, मॉडल्स अपनी कॉन्टेक्स्ट विंडो के किनारों के पास कम बेहतर प्रदर्शन करते हैं — कॉन्टेक्स्ट भरने के साथ-साथ समझने की क्षमता और निर्देशों का पालन करने की क्षमता घटती जाती है। 95% पर चलना तकनीकी रूप से संभव है, लेकिन 50% पर चलने के अनुभव जैसा बिल्कुल नहीं है।"
  ]
}
